scwin.hourCheck = async function () {
  return true;
};
scwin.hourNullCheck = async function () {
  for (i = 0; i < ds_emp2.getTotalRow(); i++) {
    if (ds_emp2.getRowStatusValue(i) == "3") {
      if (ds_emp2.getCellData(i, "arvHh") == "") {
        ds_emp2.setCellData(i, "arvDt", "");
      }
      if (ds_emp2.getCellData(i, "dptHh") == "") {
        ds_emp2.setCellData(i, "dptDt", "");
      }
      let chkVal = await dscommon.cf_gidHourNullCheck(ds_emp2.getCellData(i, "arvHh"));
      if (!chkVal) {
        ds_emp2.setRowPosition(i);
        // gr_emp2.ColSelect = "true"; // ???
        await $c.gus.cfAlertMsg($p, i + "번째 도착시간을 정확한 시간을 입력하세요");
        gr_emp2.setFocusedCell(ds_emp2.getRowPosition(), "arvHh");
        return false;
      }
    }
  }
  return true;
};

//-------------------------------------------------------------------------
// 출발일시 from ~ to 체크 함수
//-------------------------------------------------------------------------
scwin.f_DifferBetweenDate = function (sDateStr, eDateStr, dateFormat, row) {
  sDateStr = sDateStr.trim();
  eDateStr = eDateStr.trim();
  if (eDateStr == "00" || sDateStr == "00") {
    return true;
  }
  // 종료일자가 시작일자 이후인지 확인
  if (sDateStr >= eDateStr) {
    return false;
  }
  return true;
};

