// function name : f_crryInOutEDI
// function desc : 반출입예정정보EDI등록
//-------------------------------------------------------------------------
scwin.f_crryInOutEDI = function (bAlertFlag, bSaveFlag, bTransferFlag, row, bDeleteFlag) {
  if (ds_emp.getTotalRow() == 0) {
    return;
  }
  let rowData = ds_emp.getRowJSON(row);
  if (rowData["vehclNo"] == "") {
    if (bAlertFlag) {
      $c.gus.cfAlertMsg($p, "운송차량이 없습니다");
    }
    return false;
  }
  if (rowData["crryinEdiFlag"] == "N" && rowData["crryoutEdiFlag"] == "N") {
    if (bAlertFlag) {
      $c.gus.cfAlertMsg($p, "EDI등록 대상이 아닙니다");
    }
    return false;
  }
  var rtnList = new Array();
  var arrParam = new Array();
  arrParam[0] = new Array("" //조회구분 ("" : 운송작업지시, "1" : 반출입)
  , rowData["transWrkIndictNo"], rowData["odrNo"], rowData["cntrSeq"], rowData["wrkPathSeq"], rowData["wrkStpSeq"], rowData["vehclShortCd"], rowData["vehclNo"], rowData["vehclIdCardNo"], rowData["wrkStDtm"], rowData["wrkEndDtm"], rowData["cntrNo"], rowData["dptWrkPlCd"], rowData["arvWrkPlCd"], rowData["dptWrkPlCdNm"], rowData["arvWrkPlCdNm"], rowData["crryoutEdiType"], rowData["crryinEdiType"]);
  var pURL = "/ds/op/wrkplan/transwrkplan/op_202_02_21p.jsp?paramTitle=반출입예정정보EDI등록" + "&crryoutEdiType=" + rowData["crryoutEdiType"] + "&crryinEdiType=" + rowData["crryinEdiType"];
  let opts = {
    id: "pupup",
    modal: true,
    type: "browserPopup",
    width: 850,
    height: 750
  };

  // rtnList = window.showModalDialog(pURL, arrParam, "dialogWidth:850px; dialogHeight:750px");
  rtnList = $c.win.openPopup($p, pURL, opts, arrParam);
  return true;
};

